with detail = 1 {
    with link = "line.dk.FBM" {
        let fb = path("d1.dk.fbm");

        with railway = :first :pax :removed {
            track(fb[:fun.yb, :ejs.yr]);
            track(fb[:ejs.yr, :brd.yf]);
            track(fb[:brd.yb, :gri.yf]);
        }

        with railway = :first :pax :closed {
            track(fb[:gri.yb, :bra.yf]);
        }
    }

    with link = "line.dk.FPB" {
        let fa = path("d1.dk.ffh.1");
        let af = path("d1.dk.ffh.2");

        with railway = :first :double :pax {
            track(fa[:fre, :vej.yh]);
            track(fa[:vej.yh, :hor.yj]);
            track(fa[:hor.yj, :hor.yt]);
            track(fa[:hor.yt, :ska.ys]);
            track(fa[:ska.ys, :vib.yo]);
            track(fa[:vib.yo, :aar.yr]);
            track(fa[:aar.yr, :aar]);
            track(af[:aar.yr, :lau.ys]);
            track(af[:lau.ys, :lan.ya]);
            track(af[:lan.ya, :ste.yr]);
            track(af[:ste.yr, :ran.yr]);
            track(af[:ran.yr, :ran.yh]);
            track(af[:ran.yh, :ran.yf]);
            track(:removed, path("d1.dk.ffh.ste")[:ste.yr, :ran.yf]);
            track(af[:ran.yf, :far.yv]);
            track(af[:far.yv, :far.ym]);
            track(af[:far.ym, :hob.ya]);
            track(af[:hob.ya, :sve.yh]);
            track(af[:sve.yh, :aal.yh]);
            track(af[:aal.yh, :lfn]);
            track(af[:lfn, :lin.yl]);
        }

        with railway = :first :pax {
            track(af[:lin.yl, :hjo.yh]);
            track(af[:hjo.yh, :fre.ys]);
            track(af[:fre.ys, :fre]);
        }
    }


    with link = "line.dk.FPB" {
        let fp = path("d1.dk.fpb");

        with railway = :first :double :cat:ac25 :pax {
            track(fp[:fre.yt, :tau.ys]);
            track(fp[:tau.ys, :kol]);
            track(fp[:kol, :lun.ye]);
            track(fp[:lun.ye, :vam]);
            track(fp[:vam, :voj.yh]);
            track(fp[:voj.yh, :oje]);
            track(fp[:oje, :hov]);
            track(fp[:hov, :rod.ya]);
            track(fp[:rod.ya, :tin.yt]);
            track(fp[:tin.yt, :tin.ys]);
        }
        with railway = :first :cat:ac25 :pax {
            track(fp[:tin.ys, :pad.yt]);
            track(fp[:pad.yt, :pad]);
        }
        track(:first :double :cat:ac15 :pax, fp[:pad, :pag]);
    }
}

